      members.delete(user.id);
      room.members = room.members.filter((m) => m.id !== user.id);

      const currentUser = users.get(user.id);

      pubsub.publish(`${USER_LEFT}.${validRoomId}`, {
        userPresence: {
          userId: user.id,
          username: currentUser ? currentUser.username : 'Unknown',
          roomId: validRoomId,
          action: 'LEFT',
        },
      });

