// Simple token-based auth (replace with JWT/OAuth in production)
function getUserFromToken(token) {
  if (!token) return null;

  // Remove "Bearer " prefix if present
  const cleanToken = token.replace(/^Bearer\s+/i, '').trim();

  // In this MVP, the token is the user ID
  // In production, use JWT verification
  const user = users.get(cleanToken);
  if (user) {
    return { id: user.id, username: user.username };
  }
  return null;
}

async function startServer() {
  const app = express();
  const httpServer = http.createServer(app);

  // HTTP rate limiting
  const apiLimiter = rateLimit({
    windowMs: 1 * 60 * 1000, // 1 minute
    max: 100, // limit each IP to 100 requests per minute
    standardHeaders: true,
    legacyHeaders: false,
    message: 'Too many requests, please try again later.',
  });

  app.use('/graphql', apiLimiter);

  const schema = makeExecutableSchema({ typeDefs, resolvers });

  // WebSocket server for subscriptions
  const wsServer = new WebSocketServer({
    server: httpServer,
    path: '/graphql',
    // Limit max connections
    maxPayload: 1024 * 64, // 64KB max payload
  });

  // Track active WebSocket connections
  const activeConnections = new Map();
  const MAX_CONNECTIONS_PER_IP = 5;

  wsServer.on('connection', (ws, req) => {
    const ip = req.socket.remoteAddress;
    const currentCount = activeConnections.get(ip) || 0;

    if (currentCount >= MAX_CONNECTIONS_PER_IP) {
      ws.close(4429, 'Too many connections from this IP');
      return;
    }

    activeConnections.set(ip, currentCount + 1);

    ws.on('close', () => {
      const count = activeConnections.get(ip) || 1;
      if (count <= 1) {
        activeConnections.delete(ip);
      } else {
        activeConnections.set(ip, count - 1);
      }
    });
  });

  const serverCleanup = useServer(
    {
      schema,
      context: async (ctx) => {
        // Authenticate WebSocket connections via connectionParams
        const token =
          ctx.connectionParams?.authToken || ctx.connectionParams?.Authorization || null;
        const user = getUserFromToken(token);

        if (!user) {
          throw new Error('Authentication required for subscriptions.');
        }

        const connectionId = uuidv4();

        return {
          user,
          connectionId,
        };
      },
      onConnect: async (ctx) => {
        const token =
          ctx.connectionParams?.authToken || ctx.connectionParams?.Authorization || null;
        const user = getUserFromToken(token);

        if (!user) {
          return false; // Reject the connection
        }

        return true;
      },
      onDisconnect: async () => {
        // Cleanup on disconnect
      },
    },
    wsServer
  );

  const server = new ApolloServer({
    schema,
    plugins: [
      ApolloServerPluginDrainHttpServer({ httpServer }),
      {
        async serverWillStart() {
          return {
            async drainServer() {
              await serverCleanup.dispose();
            },
          };
        },
      },
    ],
    validationRules: [
      depthLimit(5), // Prevent deeply nested queries
      createComplexityLimitRule(1000, {
        // Limit query complexity
        scalarCost: 1,
        objectCost: 5,
        listFactor: 10,
      }),
    ],
    introspection: process.env.NODE_ENV !== 'production', // Disable introspection in production
    // Disable suggestions in error messages
    formatError: (formattedError) => {
      // Don't expose internal errors to clients
      if (formattedError.extensions?.code === 'INTERNAL_SERVER_ERROR') {
        return {
          message: 'An internal error occurred.',
          extensions: {
            code: 'INTERNAL_SERVER_ERROR',
          },
        };
      }

      // Remove stack traces
      const { extensions, ...rest } = formattedError;
      const { stacktrace, ...safeExtensions } = extensions || {};

      return {
        ...rest,
        extensions: safeExtensions,
      };
    },
  });

  await server.start();

  app.use(
    '/graphql',
    cors({
      origin: process.env.ALLOWED_ORIGINS
        ? process.env.ALLOWED_ORIGINS.split(',')
        : ['http://localhost:3000'],
      credentials: true,
    }),
    express.json({ limit: '64kb' }), // Limit request body size
    expressMiddleware(server, {
      context: async ({ req }) => {
        const token = req.headers.authorization || '';
        const user = getUserFromToken(token);

        return {
          user,
          ip: req.ip,
        };
      },
    })
  );

  // Health check endpoint
  app.get('/health', (_, res) => {
    res.status(200).json({ status: 'ok' });
  });

  const PORT = process.env.PORT || 4000;

  httpServer.listen(PORT, () => {
    console.log(`Server ready at http://localhost:${PORT}/graphql`);
    console.log(`WebSocket subscriptions ready at ws://localhost:${PORT}/graphql`);
    console.log(`Health check at http://localhost:${PORT}/health`);

    // Create a demo user and room for testing
    const demoUser = {
      id: 'demo-user-1',
      username: 'DemoUser',
      avatar: null,
      isOnline: true,
    };
    users.set(demoUser.id, demoUser);

    const demoRoom = {
      id: 'demo-room-1',
      name: 'General',
      description: 'General chat room for testing',
      members: [demoUser],
      createdAt: new Date().toISOString(),
      createdBy: demoUser,
    };
    rooms.set(demoRoom.id, demoRoom);
    roomMembers.set(demoRoom.id, new Set([demoUser.id]));
    messages.set(demoRoom.id, []);

    console.log(`\nDemo user created with token: demo-user-1`);
    console.log(`Demo room created with ID: demo-room-1`);
    console.log(`\nUse Authorization header: "Bearer demo-user-1" for HTTP requests`);
    console.log(
      `Use connectionParams: { authToken: "demo-user-1" } for WebSocket subscriptions`
    );
  });

  // Periodic cleanup of rate limiter maps
  setInterval(() => {
    const now = Date.now();
    for (const [key, value] of messageRateLimiter) {
      if (now > value.resetTime) {
        messageRateLimiter.delete(key);
      }
    }
    for (const [key, value] of subscriptionRateLimiter) {
      if (now > value.resetTime) {
        subscriptionRateLimiter.delete(key);
      }
    }
  }, 60000);
}

startServer().catch((err) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});